#include<bits/stdc++.h>
using namespace std;
typedef long long ll;
ll n,m,t;
const ll N=1e4+10;
ll dis[N],pre[N],cnt[N];
bool vis[N];
struct edge
{
    ll to,val;
};
vector<edge> mp[N];
vector<ll> mp2[N];
void dfs(ll x,ll fa)
{
    for(ll i:mp2[x])
    {
        if(i==fa)
        {
            continue;
        }
        dfs(i,x);
        cnt[x]+=cnt[i];
    }
}
void dijkstra()
{
    memset(dis,0x3f,sizeof(dis));
    dis[1]=0;
    priority_queue<pair<ll,ll>> q;
    q.push(make_pair(0,1));
    while(!q.empty())
    {
        pair<ll,ll> t=q.top();
        q.pop();
        ll u=t.second;
        if(vis[u])
        {
            continue;
        }
        vis[u]=1;
        for(edge i:mp[u])
        {
            ll v=i.to;
            if(dis[v]>dis[u]+i.val)
            {
                dis[v]=dis[u]+i.val;
                q.push(make_pair(-dis[v],v));
                pre[v]=u;
            }
            else if(dis[v]==dis[u]+i.val)
            {
                pre[v]=min(u,pre[v]);
            }
        }
    }
}
int main()
{
    scanf("%lld%lld%lld",&n,&m,&t);
    for(ll i=1;i<=n;i++)
    {
        scanf("%lld",&cnt[i]);
    }
    for(ll i=1;i<=m;i++)
    {
        ll a,b,t;
        scanf("%lld%lld%lld",&a,&b,&t);
        mp[a].push_back((edge){b,t});
        mp[b].push_back((edge){a,t});
    }
    dijkstra();
    for(ll i=1;i<=n;i++)
    {
        mp2[pre[i]].push_back(i);
        mp2[i].push_back(pre[i]);
    }
    dfs(1,0);
    ll ans=0;
    for(ll i=1;i<=n;i++)
    {
        ans=max(ans,cnt[i]*(dis[i]-t));
    }
    printf("%lld",ans);
    return 0;
}
